--

BEGIN;

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM users WHERE email = 'nick@riduck.com') THEN
    RAISE EXCEPTION 'User nick@riduck.com not found.';
  END IF;
END $$;

