SELECT
  'ffb5c377-3d57-4c22-a52c-fcfc02512cb2',
  id,
  '남해 보물섬 순환',
  '남해의 푸른 바다와 해안 절경을 감상하며 달릴 수 있는 보물섬 순환 코스입니다. 

